import React from 'react';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faHtml5, faCss3Alt, faJs, faBootstrap, faReact, faWordpress } from '@fortawesome/free-brands-svg-icons';
import { faMobileScreenButton } from '@fortawesome/free-solid-svg-icons';

const Skills = () => {
    return (
        <section>
            <div className="container">
                <h2 style={{ textAlign: 'center', color: 'var(--accent-color)' }}>Skills</h2>
                <div className="cards">
                    <div className="card"><FontAwesomeIcon icon={faHtml5} /> HTML</div>
                    <div className="card"><FontAwesomeIcon icon={faCss3Alt} /> CSS</div>
                    <div className="card"><FontAwesomeIcon icon={faJs} /> JavaScript/JQuery</div>
                    <div className="card"><FontAwesomeIcon icon={faBootstrap} /> Bootstrap</div>
                    <div className="card"><FontAwesomeIcon icon={faReact} /> React</div>
                    <div className="card"><FontAwesomeIcon icon={faWordpress} /> Wordpress</div>
                    <div className="card"><FontAwesomeIcon icon={faMobileScreenButton} /> Responsive Design</div>
                </div>
            </div>
        </section>
    );
};

export default Skills;
